#### GUI-REV-004: Component Inspector & Property Editor
**Points: 3 | Priority: High**

**Description:** Advanced component property editor with live preview and performance optimization suggestions.

**Revolutionary Features:**
- Live property editing with instant visual feedback
- Performance impact indicators for property changes
- AI-powered property optimization suggestions
- Property animation timeline editor
- Bulk property editing across multiple components
- Property templates and presets system

**Property Editor Interface:**
```svelte
<!-- ComponentInspector.svelte -->
<script lang="ts">
  import type { BaseComponent } from '@psyforge/forgescript';

  export let selectedComponent: BaseComponent | null;

  $: properties = selectedComponent?.getEditableProperties() || [];

  function updateProperty(key: string, value: any) {
    if (selectedComponent) {
      selectedComponent.setProperty(key, value);
      // Trigger real-time update
      canvas.invalidateComponent(selectedComponent);
    }
  }

  function optimizeProperties() {
    if (selectedComponent) {
      const suggestions = ai.optimizeComponentProperties(selectedComponent);
      applyOptimizations(suggestions);
    }
  }
</script>

<div class="component-inspector">
  {#if selectedComponent}
    <h3>Component Properties</h3>

    {#each properties as property}
      <PropertyEditor
        {property}
        on:change={(e) => updateProperty(property.key, e.detail.value)}
      />
    {/each}

    <button on:click={optimizeProperties}>
      🤖 AI Optimize
    </button>
  {/if}
</div>
```

